/* wms-outbound-obConfirmManager-sql-oracle.xml - updatePickingDetailRvsQty - 피킹상세 원복수량 수정 */
UPDATE TWORK_INFO_PI_DT
SET RVSQTY = RVSQTY + #{rvsqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND PIDTKEY = #{pidtkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updatePickingTotalDetailPickingFailQty - PICKFAIL 이동대상 총량피킹상세 피킹실패수량 UP */
UPDATE TWORK_INFO_PI_TOT_DT
SET PKFAILQTY = PKFAILQTY + #{pkfailqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND IVATKEY = #{ivatkey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateOutboundDetailByConfirm - 릴리즈상세 출고확정처리 */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = CASE WHEN 0 = (CNFRMQTY + #{cnfrmqty}) THEN '60' /*60:미출고*/
						WHEN INITQTY > (CNFRMQTY + #{cnfrmqty}) THEN '65' /*65:부분출고*/
						WHEN INITQTY = (CNFRMQTY + #{cnfrmqty}) THEN '70' /*70:출고완료*/
						ELSE OBDTSTATUSCD END
	,NISQTY = NISQTY + #{nisqty}
	,CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	,OBCNFRMDATE = #{sysdate}
	,OBCONFIRMURKEY = #{surkey}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateOutboundHeaderByConfirm - 릴리즈헤더 출고확정처리 */
UPDATE TWORK_INFO_OB_HD
SET OBCNFRMDATE = #{sysdate}
	,OBDDLNSNDRSLTCD = '00' /*출고 마감 송신 결과 코드 - 대기(00)*/
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateOutboundOrderDetailByConfirm - 오더상세 출고확정처리 */
UPDATE TWORK_INFO_OB_ORD_DT
SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	,OBCNFRMDATE = #{sysdate}
	,OBCONFIRMURKEY = #{surkey}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBORDKEY = #{obordkey}
AND OBORDDTKEY = #{oborddtkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateOutboundOrderHeaderByConfirm - 오더헤더 출고확정처리 */
UPDATE TWORK_INFO_OB_ORD_HD ORD
SET ORD.OBCNFRMDATE = #{sysdate}
	,ORD.UPDATEDATE = #{sysdate}
	,ORD.UPDATEURKEY = #{surkey}
WHERE ORD.CTKEY = #{ctkey}
AND ORD.OWKEY = #{owkey}
AND ORD.OBORDKEY = #{obordkey}
AND NOT EXISTS (
	SELECT 1
	FROM TWORK_INFO_OB_HD OH
	WHERE OH.CTKEY = ORD.CTKEY
	AND OH.OWKEY = ORD.OWKEY
	AND OH.OBORDKEY = ORD.OBORDKEY
	AND OH.OBSTATUSCD NOT IN ('60','65','70','97','98') /* 미출고,부분출고,출고완료,작업취소,결품취소 가 아닌 건 (출고가 종료되지 않은건이 존재 시)*/
)

