/* wms-outbound-obConfirmManager-sql-oracle.xml - selectOutboundDetailListForInterfaceSend - 출고상세 / 출고마감 IF 송신 데이터 조회 */
SELECT
	ORDTKEY
	,OBCNFRMDATE
	,CASE
		WHEN COALESCE(#{niscd}, 'EMPTY') != 'EMPTY' THEN #{niscd}
		WHEN INITQTY  >  CNFRMQTY THEN '03' /* 2025-12-24 KJH 결품코드 조건 변경 */
		WHEN OBDTSTATUSCD IN ('97') THEN '07' END AS NISCD
	,ICKEY
	,UOM
	,INITQTY AS EXPCTQTY
	,CNFRMQTY
FROM TWORK_INFO_OB_DT
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}

