/* wms-outbound-obConfirmManager-sql-oracle.xml - updatePickingDetailObCnfrmQty - 피킹상세 출고확정수량 수정 */
UPDATE TWORK_INFO_PI_DT
SET OBCNFRMQTY = OBCNFRMQTY + #{obcnfrmqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND PIDTKEY = #{pidtkey}

mapper.select:
/* wms-outbound-obConfirmManager-sql-oracle.xml - selectMoveOutboundHeaderForInterfaceSend - 출고마감 IF 송신 데이터 조회 BY 이고출고 용기별마감 */
SELECT
	OH.CTKEY
	,OH.OWKEY
	,OH.OBHDKEY
	,OH.OBORDKEY
	,OH.ORHDKEY
	,OH.OBSTATUSCD
	,MC.CNTRBARCODE AS CNTRCD
	,MC.MVOBGRPNO
FROM TWORK_INFO_OB_HD OH
	INNER JOIN TWORK_INFO_MVOB_CNTR MC
		ON OH.CTKEY = MC.CTKEY
		AND OH.OWKEY = MC.OWKEY
		AND OH.OBHDKEY = MC.OBHDKEY
WHERE OH.CTKEY = #{ctkey}
AND OH.OWKEY = #{owkey}
AND OH.OBHDKEY = #{obhdkey}
AND MC.MVOBGRPNO = #{mvobgrpno}
AND MC.CNTRBARCODE = #{cntrbarcode}

