/* wms-outbound-obConfirmManager-sql-oracle.xml - updateWaveHeaderWorkStatusCdByConfirm - 웨이브 작업완료 처리 */
UPDATE TWORK_INFO_WA_HD WH
SET WAWKSTATUSCD = '60'
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND WAHDKEY = #{wahdkey}
AND WAWKSTATUSCD = '50'
AND NOT EXISTS ( /*미출고, 부분출고, 출고완료, 결품보류, 결품보류확정, 작업취소 가 아닌건이 존재하지 않으면 UPDATE */
	SELECT 1
	FROM TWORK_INFO_WA_DT WD
	INNER JOIN TWORK_INFO_OB_HD OH
		ON WD.CTKEY = OH.CTKEY
		AND WD.OWKEY = OH.OWKEY
		AND WD.OBHDKEY = OH.OBHDKEY
	WHERE WD.CTKEY = WH.CTKEY
	AND WD.OWKEY = WH.OWKEY
	AND WD.WAHDKEY = WH.WAHDKEY
	AND OH.OBSTATUSCD NOT IN ('60', '65', '70', '80', '85', '97') /*미출고, 부분출고, 출고완료, 결품보류, 결품보류확정, 작업취소 가 아닌건이 존재하는지 색인*/
)

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateObWkCnlObDt - 재고이동 후 릴리즈 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = '97'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateObWkCnlObHd - 작업취소 후 릴리즈 헤더 상태값 변경 */
UPDATE TWORK_INFO_OB_HD
   SET OBSTATUSCD = '97'
	 , OBDDLNSNDRSLTCD = '00' /*출고 마감 송신 결과 코드 - 대기(00)*/
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-obConfirmManager-sql-oracle.xml - updateOutboundHeaderIfSendResultCd - 출고헤더 인터페이스 송신결과 저장 */
UPDATE TWORK_INFO_OB_HD
   SET OBDDLNSNDRSLTCD = #{obddlnsndrsltcd}
	 , OBDDLNSNDRSLTMSG = #{obddlnsndrsltmsg}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
